import { guardProcessEnv } from "./helpers/env-guard.js";
guardProcessEnv();

/**
 * Unit tests for generateToolGuardExtension.
 *
 * Motivation: a prior bug used `\"` inside a backtick template literal for the
 * never-policy error message. The escape consumed the quote, producing
 * `"" + toolName + ""` and a TS ParseError that crashed every new session with
 * a role owning a never-policy tool. This spec exists to catch any recurrence.
 *
 * Strategy: for each of 4 policy-input variants, assert
 *   1. Parse-validity — TS transpile emits no error diagnostics.
 *   2. Round-trip import — transpiled CJS loads and default-exports a function.
 *   3. Branch presence — `neverPolicies = {}` literal appears iff no never-tool
 *      was supplied (same sanity check for `askPolicies`).
 */
import assert from "node:assert/strict";
import { createRequire } from "node:module";
import { describe, it } from "vitest";
import ts from "typescript";

import {
	generateToolGuardExtension,
	type ToolPolicyEntry,
} from "../../src/server/agent/tool-guard-extension.ts";

type GuardPi = { on: (event: string, cb: (event: any) => Promise<any>) => void };
type GuardFactory = (pi: GuardPi) => void;

const require = createRequire(import.meta.url);
let grantPolicy: ((count: number) => unknown) | undefined;
let grantRequestCount = 0;

function transpileGuard(source: string): ReturnType<typeof ts.transpileModule> {
	return ts.transpileModule(source, {
		compilerOptions: {
			module: ts.ModuleKind.CommonJS,
			target: ts.ScriptTarget.ES2020,
		},
		reportDiagnostics: true,
	});
}

function evaluateCommonJs(source: string, requestGrant: () => Promise<unknown>): GuardFactory {
	const transpiled = transpileGuard(source);
	const errors = (transpiled.diagnostics ?? []).filter((diagnostic) => diagnostic.category === ts.DiagnosticCategory.Error);
	assert.equal(errors.length, 0);
	const module = { exports: {} as { default?: GuardFactory } };
	new Function("module", "exports", "require", "requestGrant", transpiled.outputText)(module, module.exports, require, requestGrant);
	assert.equal(typeof module.exports.default, "function");
	return module.exports.default!;
}

function withInjectedGrantTransport(source: string): string {
	const start = source.indexOf("      const mod = url.protocol");
	const endMarker = "      const r = result;";
	const end = source.indexOf(endMarker, start);
	assert.ok(start >= 0 && end > start, "generated guard transport block changed");
	return `${source.slice(0, start)}      const result = await requestGrant(JSON.parse(body));\n\n${source.slice(end)}`;
}

async function importGeneratedGuard(source: string, _name: string): Promise<GuardFactory> {
	return evaluateCommonJs(withInjectedGrantTransport(source), async () => {
		grantRequestCount += 1;
		assert.ok(grantPolicy, "grant policy must be installed before invoking an ask guard");
		return grantPolicy(grantRequestCount);
	});
}

async function withGrantServer(
	responseForRequest: (count: number) => unknown,
	run: (requestCount: () => number) => Promise<void>,
): Promise<void> {
	const previousSessionId = process.env.BOBBIT_SESSION_ID;
	grantPolicy = responseForRequest;
	grantRequestCount = 0;
	process.env.BOBBIT_SESSION_ID = "tool-guard-test-session";
	try {
		await run(() => grantRequestCount);
	} finally {
		grantPolicy = undefined;
		if (previousSessionId === undefined) delete process.env.BOBBIT_SESSION_ID;
		else process.env.BOBBIT_SESSION_ID = previousSessionId;
	}
}

interface Variant {
	name: string;
	policies: Record<string, ToolPolicyEntry>;
	hasAsk: boolean;
	hasNever: boolean;
}

const variants: Variant[] = [
	{
		name: "allow-only",
		// 'allow' entries are filtered out by the generator — both maps serialize to {}.
		policies: {
			read: { policy: "allow", group: "fs" },
			write: { policy: "allow", group: "fs" },
		},
		hasAsk: false,
		hasNever: false,
	},
	{
		name: "ask-only",
		policies: {
			bash: { policy: "ask", group: "shell" },
		},
		hasAsk: true,
		hasNever: false,
	},
	{
		name: "never-only",
		// The original-bug shape: role denies a tool outright.
		policies: {
			bash_bg: { policy: "never", group: "shell" },
		},
		hasAsk: false,
		hasNever: true,
	},
	{
		name: "mixed",
		policies: {
			read: { policy: "allow", group: "fs" },
			bash: { policy: "ask", group: "shell" },
			bash_bg: { policy: "never", group: "shell" },
		},
		hasAsk: true,
		hasNever: true,
	},
	{
		// Contributor-role shape: gate_signal denied so non-team-lead agents
		// cannot call it (see tests/role-gate-signal-policy.test.ts for the
		// per-role invariant).
		name: "gate-signal-never",
		policies: {
			gate_signal: { policy: "never", group: "gates" },
		},
		hasAsk: false,
		hasNever: true,
	},
];

describe("generateToolGuardExtension", () => {
	for (const v of variants) {
		describe(v.name, () => {
			const source = generateToolGuardExtension("sess-" + v.name, v.policies, []);

			const transpiled = ts.transpileModule(source, {
				compilerOptions: {
					module: ts.ModuleKind.CommonJS,
					target: ts.ScriptTarget.ES2020,
				},
				reportDiagnostics: true,
			});

			it("emits no TypeScript error diagnostics", () => {
				const errors = (transpiled.diagnostics ?? []).filter(
					(d) => d.category === ts.DiagnosticCategory.Error,
				);
				const msg = errors
					.map((d) => ts.flattenDiagnosticMessageText(d.messageText, "\n"))
					.join("\n");
				assert.equal(errors.length, 0, `Expected no error diagnostics, got:\n${msg}`);
			});

			it("transpiled module loads and default-exports a function", () => {
				const module = { exports: {} as { default?: GuardFactory } };
				new Function("module", "exports", "require", transpiled.outputText)(module, module.exports, require);
				assert.equal(typeof module.exports.default, "function");
			});

			it("neverPolicies branch presence matches input", () => {
				assert.equal(
					source.includes("neverPolicies = {}"),
					!v.hasNever,
					v.hasNever
						? "expected neverPolicies to be populated"
						: "expected neverPolicies to serialize to {}",
				);
			});

			it("askPolicies branch presence matches input", () => {
				assert.equal(
					source.includes("askPolicies = {}"),
					!v.hasAsk,
					v.hasAsk
						? "expected askPolicies to be populated"
						: "expected askPolicies to serialize to {}",
				);
			});

			if (v.name === "gate-signal-never") {
				it("contains a runtime refusal branch keyed on gate_signal", () => {
					assert.ok(
						source.includes('"gate_signal"'),
						"expected generated source to include the gate_signal tool name",
					);
					assert.ok(
						source.includes("neverPolicies[toolName]"),
						"expected generated source to gate calls via neverPolicies",
					);
				});
			}
		});
	}

	it("uses gateway-owned runtime session identity instead of embedding it in shared source", () => {
		const source = generateToolGuardExtension("must-not-be-embedded", { bash: { policy: "ask", group: "shell" } }, []);
		assert.equal(source.includes("must-not-be-embedded"), false);
		assert.ok(source.includes("process.env.BOBBIT_SESSION_ID"));
		assert.ok(source.includes("missing BOBBIT_SESSION_ID"));
	});

	it("does not cache one-time grant responses in the active guard", async () => {
		const guard = await importGeneratedGuard(
			generateToolGuardExtension("sess-one-time", { bash: { policy: "ask", group: "shell" } }, []),
			"one-time",
		);
		await withGrantServer(
			(count) => count === 1
				? { granted: true, mode: "one-time", scope: "tool", tools: ["bash"] }
				: { granted: false, reason: "second ask" },
			async (requestCount) => {
				let onToolCall: ((event: any) => Promise<any>) | undefined;
				guard({ on: (_event, cb) => { onToolCall = cb; } });
				assert.ok(onToolCall);
				assert.deepEqual(await onToolCall!({ toolName: "bash" }), { block: false });
				assert.deepEqual(await onToolCall!({ toolName: "bash" }), { block: true, reason: "second ask" });
				assert.equal(requestCount(), 2, "one-time grants must not populate the process-local grant cache");
			},
		);
	});

	it("continues caching session-scoped grant responses in the active guard", async () => {
		const guard = await importGeneratedGuard(
			generateToolGuardExtension("sess-session-only", { bash: { policy: "ask", group: "shell" } }, []),
			"session-only",
		);
		await withGrantServer(
			(count) => count === 1
				? { granted: true, mode: "session-only", scope: "tool", tools: ["bash"] }
				: { granted: false, reason: "unexpected second ask" },
			async (requestCount) => {
				let onToolCall: ((event: any) => Promise<any>) | undefined;
				guard({ on: (_event, cb) => { onToolCall = cb; } });
				assert.ok(onToolCall);
				assert.deepEqual(await onToolCall!({ toolName: "bash" }), { block: false });
				assert.equal(await onToolCall!({ toolName: "bash" }), undefined);
				assert.equal(requestCount(), 1, "session-only grants should remain cached for the active guard");
			},
		);
	});

	it("blocks granted responses that do not cover the current tool", async () => {
		const guard = await importGeneratedGuard(
			generateToolGuardExtension("sess-mismatched-tool", {
				bash: { policy: "ask", group: "shell" },
				read: { policy: "ask", group: "fs" },
			}, []),
			"mismatched-tool",
		);
		await withGrantServer(
			() => ({ granted: true, mode: "session-only", scope: "tool", tools: ["read"] }),
			async () => {
				let onToolCall: ((event: any) => Promise<any>) | undefined;
				guard({ on: (_event, cb) => { onToolCall = cb; } });
				assert.ok(onToolCall);
				assert.deepEqual(await onToolCall!({ toolName: "bash" }), {
					block: true,
					reason: "Permission grant did not cover tool bash",
				});
			},
		);
	});

	it("requires one-time grant responses to cover the blocked invocation", async () => {
		const guard = await importGeneratedGuard(
			generateToolGuardExtension("sess-one-time-mismatch", {
				bash: { policy: "ask", group: "shell" },
				bash_bg: { policy: "ask", group: "shell" },
			}, []),
			"one-time-mismatch",
		);
		await withGrantServer(
			() => ({ granted: true, mode: "one-time", scope: "group", group: "shell", tools: ["bash_bg"] }),
			async () => {
				let onToolCall: ((event: any) => Promise<any>) | undefined;
				guard({ on: (_event, cb) => { onToolCall = cb; } });
				assert.ok(onToolCall);
				assert.deepEqual(await onToolCall!({ toolName: "bash" }), {
					block: true,
					reason: "Permission grant did not cover tool bash",
				});
			},
		);
	});

	it("accepts MCP group grants that include the model-facing meta-tool only for that group", async () => {
		const guard = await importGeneratedGuard(
			generateToolGuardExtension("sess-mcp-meta-group", {
				mcp_mock: { policy: "ask", group: "MCP: mock" },
				mcp__mock__echo: { policy: "ask", group: "MCP: mock" },
				session_prompt: { policy: "ask", group: "Agent" },
			}, []),
			"mcp-meta-group",
		);
		await withGrantServer(
			(count) => count === 1
				? { granted: true, mode: "session-only", scope: "group", group: "MCP: mock", tools: ["mcp__mock__echo", "mcp_mock"] }
				: { granted: false, reason: "session_prompt still ask-gated" },
			async (requestCount) => {
				let onToolCall: ((event: any) => Promise<any>) | undefined;
				guard({ on: (_event, cb) => { onToolCall = cb; } });
				assert.ok(onToolCall);
				assert.deepEqual(await onToolCall!({ toolName: "mcp_mock" }), { block: false });
				assert.equal(await onToolCall!({ toolName: "mcp_mock" }), undefined);
				assert.deepEqual(await onToolCall!({ toolName: "session_prompt" }), {
					block: true,
					reason: "session_prompt still ask-gated",
				});
				assert.equal(requestCount(), 2, "MCP group grant must not cache unrelated ask-gated tools");
			},
		);
	});
});
